const js = String.raw`
(() => { const c=document.getElementById('neural-field'); if(c){const x=c.getContext('2d');let w,h,d=80,p=[];function r(){w=c.width=innerWidth;h=c.height=innerHeight;p=Array.from({length:Math.min(96,Math.floor(w*h/19000))},(_,i)=>({x:Math.random()*w,y:Math.random()*h,vx:(Math.random()-.5)*.23,vy:(Math.random()-.5)*.23,t:i%3}))}addEventListener('resize',r,{passive:true});r();(function a(){x.clearRect(0,0,w,h);for(const q of p){q.x=(q.x+q.vx+w)%w;q.y=(q.y+q.vy+h)%h;x.fillStyle=q.t? '#6fffe0':'#fff08b';x.globalAlpha=.75;x.fillRect(q.x,q.y,2,2)}x.globalAlpha=.17;x.strokeStyle='#6fffe0';for(let i=0;i<p.length;i++)for(let j=i+1;j<p.length;j++){const A=p[i],B=p[j],dx=A.x-B.x,dy=A.y-B.y,dd=Math.hypot(dx,dy);if(dd<d){x.beginPath();x.moveTo(A.x,A.y);x.lineTo(B.x,B.y);x.stroke()}}requestAnimationFrame(a)})()} const stages=['Commission','Submit','Map','Review','Accept','Receipt'];function run(log,score,state,ring){let i=0;if(log)log.textContent='';function step(){if(i<stages.length){if(log)log.textContent += '✓ '+stages[i]+' gate passed.\n';const v=Math.round(((i+1)/stages.length)*100);if(score)score.textContent=v;if(state)state.textContent=i===stages.length-1?'Ready':'Running';if(ring)ring.style.strokeDashoffset=314-(314*v/100);i++;setTimeout(step,460)}else{if(log)log.textContent+='Mission 001 replay-ready. Synthetic packet complete.\n';}}step()} document.querySelectorAll('[data-run-cycle],[data-run-mission001]').forEach(b=>b.addEventListener('click',e=>{e.preventDefault();run(document.querySelector('[data-run-log]'),document.querySelector('[data-score]'),document.querySelector('[data-state]'),document.querySelector('[data-ring]'))})); const bundle=window.GOALOS_MISSION_001_BUNDLE; function dl(name,obj){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([typeof obj==='string'?obj:JSON.stringify(obj,null,2)],{type:'application/json'}));a.download=name;document.body.appendChild(a);a.click();a.remove();} document.querySelectorAll('[data-download-mission001]').forEach(b=>b.addEventListener('click',e=>{e.preventDefault();dl('GOALOS-MISSION-001-benchmark-packet.json', bundle||{mission:'GOALOS-MISSION-001'})})); document.querySelectorAll('[data-copy-replay]').forEach(b=>b.addEventListener('click',e=>{e.preventDefault();navigator.clipboard&&navigator.clipboard.writeText('Actions -> Mission 001 Benchmark Reproducibility Packet -> Run workflow -> Download artifact')}));})();`;
